import { NextResponse } from 'next/server';

export async function POST(request) {
  try {
    const body = await request.json();
    const { number } = body;

    if (!number) {
      return NextResponse.json(
        { error: 'NIN number is required' },
        { status: 400 }
      );
    }

    const response = await fetch('https://api.prembly.com/api/v1/verification/nin', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'app-id': process.env.PREMBLY_APP_ID || '',
        'x-api-key': process.env.PREMBLY_API_KEY || '',
      },
      body: JSON.stringify({ number }),
    });

    const data = await response.json();

    if (!response.ok) {
      return NextResponse.json(
        { error: data.message || 'Verification failed', details: data },
        { status: response.status }
      );
    }

    return NextResponse.json(data);
  } catch (error) {
    console.error('NIN verification error:', error);
    return NextResponse.json(
      { error: 'Internal Server Error' },
      { status: 500 }
    );
  }
}

